#include <bits/stdc++.h>
#define int long long
#define dfdfgg vector















using namespace std;
int a[498], n, m, ans = 0x3f3f3f3f3f3f3f3f;
unordered_map<int, int> sand;
dfdfgg<int> aa, b;
void dfs(int l, int r, int sum, int gggg)
{
	if (sum > m)
	{
		return                             ;
	}
	if (l > r)
	{
		if (sand.find(sum) == sand.end())sand[sum] = gggg;
		else sand[sum] = min(sand[sum], gggg);
		return                             ;
	}
	dfs(l + 1, r, sum + a[l], gggg);
	dfs(l + 1, r, sum + a[l] / 2, gggg + 1);
	dfs(l + 1, r, sum, gggg);
}
void dfss(int l, int r, int sum, int gggg)
{
	if (gggg > ans)return                                              ;
	if (sum > m)return                                             ;
	if (l > r)
	{
		if (sand.find(m - sum) != sand.end())ans = min(ans, gggg + sand[m - sum]);
		return                             ;
	}

	dfss(l + 1, r, sum + a[l], gggg);
	dfss(l + 1, r, sum + a[l] / 2, gggg + 1);
	dfss(l + 1, r, sum, gggg);
}
signed main(void)
{
	cin >> n >> m >> a[1];
	m *= 2;
	a[1] *= 2;
	for (int i = 2; i <= n; ++i)
	{
		cin >> a[i];
		a[i] *= 2;
	}
	sort(a+1,a+n+1); 
	dfs(1, n / 2, 0, 0);
	dfss(n / 2 + 1, n, 0, 0);
	return cout << ((ans>=0x3f3f3f3f3f3f3f3f/2)?(-1):(ans)),0;
}
